-- Add trailing periods to action cell content for scenarios that already
-- received sentence-case capitalization (Discovery, Interview, Tech Setup,
-- Reporting an Issue, Reporting Hours). Before Students Join already done.

-- Discovery (happy + sad)
update public.cells
set content = content || '.'
where id in (
  'a0000000-0000-4000-8000-000000070104',
  'a0000000-0000-4000-8000-000000070404',
  'a0000000-0000-4000-8000-000000070507',
  'a0000000-0000-4000-8000-000000070603',
  'a0000000-0000-4000-8000-000000720104',
  'a0000000-0000-4000-8000-000000720404',
  'a0000000-0000-4000-8000-000000720507',
  'a0000000-0000-4000-8000-000000720603'
)
and content !~ '[.!?]$';

